// Note that we don't yet support `indirect` for enums.
// See https://github.com/mozilla/uniffi-rs/issues/396 for further discussion.
/**
 * What a [`StepHandler`] returns: zero, one, or many events to publish.
 */

public enum StepOutput: Equatable, Hashable {
    
    /**
     * Step performed work but produced no event.
     */
    case none
    /**
     * Step produced exactly one event (the common case).
     */
    case single(event: Event
    )
    /**
     * Step fans out — produced multiple events at once.
     */
    case multiple(events: [Event]
    )





}

#if compiler(>=6)
extension StepOutput: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeStepOutput: FfiConverterRustBuffer {
    typealias SwiftType = StepOutput

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> StepOutput {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .none
        
        case 2: return .single(event: try FfiConverterTypeEvent.read(from: &buf)
        )
        
        case 3: return .multiple(events: try FfiConverterSequenceTypeEvent.read(from: &buf)
        )
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: StepOutput, into buf: inout [UInt8]) {
        switch value {
        
        
        case .none:
            writeInt(&buf, Int32(1))
        
        
        case let .single(event):
            writeInt(&buf, Int32(2))
            FfiConverterTypeEvent.write(event, into: &buf)
            
        
        case let .multiple(events):
            writeInt(&buf, Int32(3))
            FfiConverterSequenceTypeEvent.write(events, into: &buf)
            
        }
    }
}


